// // When cl is 10, o should be 1; when cl is 01, o should be 0; when cl is 11, o should be 1; when cl is 00, o should be 1.
module top_module (
    input c,
    input l,
    output reg o
);
    always @(*) begin
        case ({c, l})
            2'b10: o = 1'b0;
            2'b01: o = 1'b1;
            2'b11: o = 1'b0;
            2'b00: o = 1'b0;
        endcase
    end
endmodule
